class Solution:
    def largestOverlap(self, img1, img2):
        n = len(img1)
        best = 0
        for dr in range(-(n - 1), n):
            for dc in range(-(n - 1), n):
                cnt = 0
                for i in range(n):
                    for j in range(n):
                        if img1[i][j] == 1:
                            r, c = i + dr, j + dc
                            if 0 <= r < n and 0 <= c < n and img2[r][c] == 1:
                                cnt += 1
                best = max(best, cnt)
        return best

