var largestOverlap = function(img1, img2) {
    const n = img1.length;
    const ones1 = [], ones2 = [];
    for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) {
        if (img1[i][j]) ones1.push([i, j]);
        if (img2[i][j]) ones2.push([i, j]);
    }
    const votes = new Map();
    let best = 0;
    for (const [r1, c1] of ones1) {
        for (const [r2, c2] of ones2) {
            const key = (r1 - r2) + ',' + (c1 - c2);
            const v = (votes.get(key) || 0) + 1;
            votes.set(key, v);
            if (v > best) best = v;
        }
    }
    return best;
};
